63: GrpcMuxImpl<S, F, RQ, RS>::createGrpcStreamObject(GrpcMuxContext& grpc_mux_context) {
64:   if (Runtime::runtimeFeatureEnabled("envoy.restart_features.xds_failover_support")) {
65:     return std::make_unique<GrpcMuxFailover<RQ, RS>>(
66:         /*primary_stream_creator=*/
67:         [&grpc_mux_context](GrpcStreamCallbacks<RS>* callbacks) -> GrpcStreamInterfacePtr<RQ, RS> {
68:           return std::make_unique<GrpcStream<RQ, RS>>(
69:               callbacks, std::move(grpc_mux_context.async_client_),
70:               grpc_mux_context.service_method_, grpc_mux_context.dispatcher_,
71:               grpc_mux_context.scope_, std::move(grpc_mux_context.backoff_strategy_),
72:               grpc_mux_context.rate_limit_settings_);
73:         },
74:         /*failover_stream_creator=*/
75:         grpc_mux_context.failover_async_client_
76:             ? absl::make_optional([&grpc_mux_context](GrpcStreamCallbacks<RS>* callbacks)
77:                                       -> GrpcStreamInterfacePtr<RQ, RS> {
78:                 return std::make_unique<GrpcStream<RQ, RS>>(
79:                     callbacks, std::move(grpc_mux_context.failover_async_client_),
80:                     grpc_mux_context.service_method_, grpc_mux_context.dispatcher_,
81:                     grpc_mux_context.scope_,
82:                     // TODO(adisuissa): the backoff strategy for the failover should
83:                     // be the same as the primary source.
84:                     std::make_unique<FixedBackOffStrategy>(
85:                         GrpcMuxFailover<RQ, RS>::DefaultFailoverBackoffMilliseconds),
86:                     grpc_mux_context.rate_limit_settings_);
87:               })
88:             : absl::nullopt,
89:         /*grpc_mux_callbacks=*/*this,
90:         /*dispatch=*/grpc_mux_context.dispatcher_);
91:   }
92:   return std::make_unique<GrpcStream<RQ, RS>>(
93:       this, std::move(grpc_mux_context.async_client_), grpc_mux_context.service_method_,
94:       grpc_mux_context.dispatcher_, grpc_mux_context.scope_,
95:       std::move(grpc_mux_context.backoff_strategy_), grpc_mux_context.rate_limit_settings_);
96: }
